1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	}
16	
17	interface QuoteResult {
18	  premium: number;
19	}
20	
21	const PROCESSING_FEE = 5;
22	const FIRST_INSURANCE_RATE = 0.1;
23	
24	const BASE_PREMIUM: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
34	const BLOCK_SIZE = 3;
35	const BLOCK_BASE_PREMIUM = 60;
36	
37	const isBuildingBlock = (type: string, count: number): boolean =>
38	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
39	
40	const groupBasePremium = (type: string, count: number): number =>
41	  isBuildingBlock(type, count) ? BLOCK_BASE_PREMIUM : count * BASE_PREMIUM[type];
42	
43	const countByType = (items: Item[]): Map<string, number> =>
44	  items.reduce(
45	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
46	    new Map<string, number>(),
47	  );
48	
49	const policyBase = (items: Item[]): number =>
50	  Array.from(countByType(items)).reduce(
51	    (total, [type, count]) => total + groupBasePremium(type, count),
52	    0,
53	  );
54	
55	const CURSED_RATE = 0.5;
56	const HIGH_ENCHANTMENT_RATE = 0.3;
57	const HIGH_ENCHANTMENT_THRESHOLD = 5;
58	
59	const SURCHARGE_RATES: ReadonlyArray<(item: Item) => number> = [
60	  (item) => (item.cursed ? CURSED_RATE : 0),
61	  (item) => ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0),
62	];
63	
64	const itemSurcharges = (item: Item): number => {
65	  const itemBase = BASE_PREMIUM[item.type];
66	  const totalRate = SURCHARGE_RATES.reduce((sum, rate) => sum + rate(item), 0);
67	  return itemBase * totalRate;
68	};
69	
70	const policySurcharges = (items: Item[]): number =>
71	  items.reduce((sum, item) => sum + itemSurcharges(item), 0);
72	
73	const quoteStep = ({ items }: QuoteStep): QuoteResult => {
74	  const base = policyBase(items);
75	  const surcharges = policySurcharges(items);
76	  const firstInsurance = base * FIRST_INSURANCE_RATE;
77	  return { premium: Math.ceil(base + surcharges + firstInsurance + PROCESSING_FEE) };
78	};
79	
80	export const processScenario = (scenario: Scenario): { results: QuoteResult[] } => {
81	  const results = scenario.steps.map(quoteStep);
82	  return { results };
83	};
